 1	import * as React from 'react';
 2	import { connect } from 'react-redux';
 3	import { ExpandableSection, Card, CardBody } from '@patternfly/react-core';
 4	import { MessageType, NotificationMessage } from '../../types/MessageCenter';
 5	import moment from 'moment';
 6	import { MessageCenterActions } from 'actions/MessageCenterActions';
 7	import { KialiDispatch } from 'types/Redux';
 8	import { kialiStyle } from 'styles/StyleUtils';
 9	import { KialiIcon } from 'config/KialiIcon';
10	
11	const getIcon = (type: MessageType) => {
12	  switch (type) {
13	    case MessageType.ERROR:
14	      return <KialiIcon.Error />;
15	    case MessageType.INFO:
16	      return <KialiIcon.Info />;
17	    case MessageType.SUCCESS:
18	      return <KialiIcon.Ok />;
19	    case MessageType.WARNING:
20	      return <KialiIcon.Warning />;
21	    default:
22	      throw Error('Unexpected type');
23	  }
24	};
25	
26	type ReduxProps = {
27	  markAsRead: (message: NotificationMessage) => void;
28	  toggleMessageDetail: (message: NotificationMessage) => void;
29	};
30	
31	type AlertDrawerMessageProps = ReduxProps & {
32	  message: NotificationMessage;
33	};
34	
35	class AlertDrawerMessageComponent extends React.PureComponent<AlertDrawerMessageProps> {
36	  static readonly body = kialiStyle({
37	    paddingTop: 0
38	  });
39	  static readonly left = kialiStyle({
40	    float: 'left'
41	  });
42	  static readonly right = kialiStyle({
43	    float: 'right'
44	  });
45	
46	  render() {
47	    return (
48	      <Card>
49	        <CardBody className={AlertDrawerMessageComponent.body}>
50	          {getIcon(this.props.message.type)}{' '}
51	          {this.props.message.seen ? this.props.message.content : <b>{this.props.message.content}</b>}
52	          {this.props.message.detail && (
53	            <ExpandableSection
54	              toggleText={this.props.message.showDetail ? 'Hide Detail' : 'Show Detail'}
55	              onToggle={() => this.props.toggleMessageDetail(this.props.message)}
56	              isExpanded={this.props.message.showDetail}
57	            >
58	              <pre style={{ whiteSpace: 'pre-wrap' }}>{this.props.message.detail}</pre>
59	            </ExpandableSection>
60	          )}
61	          {this.props.message.count > 1 && (
62	            <div>
63	              {this.props.message.count} {moment().from(this.props.message.firstTriggered)}
64	            </div>
65	          )}
66	          <div>
67	            <span className={AlertDrawerMessageComponent.left}>{this.props.message.created.toLocaleDateString()}</span>
68	            <span className={AlertDrawerMessageComponent.right}>{this.props.message.created.toLocaleTimeString()}</span>
69	          </div>
70	        </CardBody>
71	      </Card>
72	    );
73	  }
74	}
75	
76	const mapDispatchToProps = (dispatch: KialiDispatch) => {
77	  return {
78	    markAsRead: message => dispatch(MessageCenterActions.markAsRead(message.id)),
79	    toggleMessageDetail: message => dispatch(MessageCenterActions.toggleMessageDetail(message.id))
80	  };
81	};
82	
83	export const AlertDrawerMessage = connect(null, mapDispatchToProps)(AlertDrawerMessageComponent);

